import React from 'react';
import './App.css';

import firebase from 'firebase/compat/app';
import 'firebase/compat/firestore';  //for database
import 'firebase/compat/auth';   //for user authentication


//hooks to make life easier
import { useAuthState } from "react-firebase-hooks/auth";
import { useCollectionData } from 'react-firebase-hooks/firestore';

firebase.initializeApp({
  apiKey: "AIzaSyATs6Y5eZZ07D1On5fpxyAIIrW68IaOGUE",
  authDomain: "catsta-c4f15.firebaseapp.com",
  projectId: "catsta-c4f15",
  storageBucket: "catsta-c4f15.appspot.com",
  messagingSenderId: "523726488299",
  appId: "1:523726488299:web:20523d950013a51dd6f4ae",
  measurementId: "G-3N3S74KRW4"
})

const auth  = firebase.auth(); 
const firestore = firebase.firestore();


const [user] = useAuthState(auth);   //using this will allows easier way to check if user is logged in


//line {user ? <frontpage /> : <SignIn />} is basically like if the user is logged in show frontpage, if not show signIn
function App() {
  return (
    <div className="App">
      <header className="App-header">
      </header>
      <section>
      </section>
    </div>
  );
}


export default App;
